// ─── SHARED ATOMS ─────────────────────────────────────────────────────────────
const Tag = ({ children }) => (
  <span style={{
    display: 'inline-block',
    background: 'rgba(255,255,255,0.04)',
    border: '1px solid rgba(255,255,255,0.08)',
    padding: '0.4rem 1rem', borderRadius: '100px',
    fontSize: '0.8rem', color: '#e4e4e7',
    marginRight: '0.6rem', marginBottom: '0.5rem',
  }}>
    {children}
  </span>
);

const SectionHeader = ({ children }) => {
  const [ref, revealed] = useReveal();
  return (
    <h2 ref={ref} style={{
      fontSize: 'clamp(2rem, 4vw, 3rem)', fontWeight: 700,
      textAlign: 'center', marginBottom: '3.5rem', letterSpacing: '-1px',
      transform: revealed ? 'none' : 'translateY(40px)',
      opacity: revealed ? 1 : 0,
      transition: 'transform 0.9s cubic-bezier(0.22,1,0.36,1), opacity 0.8s ease',
    }}>{children}</h2>
  );
};

